import csv
from datetime import datetime, timezone

# Simple example: merge events from two CSV files into a unified UTC timeline

def parse_time(ts):
    # Assume input like '2026-03-21 10:15:23+02:00'
    return datetime.fromisoformat(ts).astimezone(timezone.utc)

all_events = []

for filename, source in [("fs_events.csv", "filesystem"), ("winlog_events.csv", "winlog")]:
    with open(filename, newline="", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        for row in reader:
            event_time = parse_time(row["timestamp"])
            all_events.append({
                "time_utc": event_time,
                "source": source,
                "action": row.get("action", ""),
                "details": row.get("details", ""),
            })

all_events.sort(key=lambda e: e["time_utc"])

with open("merged_timeline.csv", "w", newline="", encoding="utf-8") as f:
    fieldnames = ["time_utc", "source", "action", "details"]
    writer = csv.DictWriter(f, fieldnames=fieldnames)
    writer.writeheader()
    for e in all_events:
        writer.writerow({
            "time_utc": e["time_utc"].isoformat(),
            "source": e["source"],
            "action": e["action"],
            "details": e["details"],
        })
